// 요청 파라미터 파싱 및 쇼핑몰 목록 생성
const body = $input.first().json.body || {};
const categoryId = body.category_id || 'fashion';
const categoryName = body.category_name || '패션/의류';
const maxItems = body.max_items_per_mall || 30;

// 카테고리별 검색 키워드 매핑
const KEYWORDS = {
  fashion:     ['패션', '의류', '신발', '가방', '액세서리', '원피스', '티셔츠'],
  electronics: ['스마트폰', '노트북', '이어폰', '가전제품', '태블릿', '카메라'],
  food:        ['건강식품', '간편식', '과자', '음료', '커피', '유기농'],
  beauty:      ['화장품', '스킨케어', '마스크팩', '향수', '선크림', '립스틱'],
  furniture:   ['가구', '소파', '책상', '조명', '커튼', '침대'],
  sports:      ['운동기구', '요가매트', '등산', '자전거', '수영', '헬스'],
  baby:        ['기저귀', '분유', '유모차', '장난감', '아동복', '젖병'],
  pet:         ['강아지사료', '고양이사료', '펫용품', '리드줄', '하우스']
};

// 크롤링 대상 쇼핑몰
const MALLS = [
  { id: 'coupang',   name: '쿠팡',       endpoint: 'coupang' },
  { id: 'naver',     name: '네이버쇼핑', endpoint: 'naver' },
  { id: 'gmarket',   name: 'G마켓',      endpoint: 'gmarket' },
  { id: '11st',      name: '11번가',     endpoint: 'elevenst' },
  { id: 'ssg',       name: 'SSG닷컴',    endpoint: 'ssg' },
  { id: 'lotteon',   name: '롯데온',     endpoint: 'lotteon' }
];

const keywords = KEYWORDS[categoryId] || [categoryId];

return MALLS.map(mall => ({
  json: {
    category_id: categoryId,
    category_name: categoryName,
    mall_id: mall.id,
    mall_name: mall.name,
    endpoint: mall.endpoint,
    keywords,
    primary_keyword: keywords[0],
    max_items: maxItems
  }
}));

// 전체 쇼핑몰 결과 집계 + 중복 제거
const items = $input.all();
const seen = new Set();
const allProducts = [];

for (const item of items) {
  const products = item.json.products || [];
  for (const p of products) {
    const key = p.url || `${p.mall_id}:${p.item_id}`;
    if (!seen.has(key)) {
      seen.add(key);
      allProducts.push(p);
    }
  }
}

// 가격순 정렬 (낮은 가격 우선)
allProducts.sort((a, b) => (a.price || 999999999) - (b.price || 999999999));

const categoryId = items[0]?.json?.category_id || 'unknown';
const categoryName = items[0]?.json?.category_name || '';

return [{
  json: {
    category_id: categoryId,
    category_name: categoryName,
    crawled_at: new Date().toISOString(),
    total_count: allProducts.length,
    new_count: items.reduce((s, i) => s + (i.json.new_count || 0), 0),
    updated_count: items.reduce((s, i) => s + (i.json.updated_count || 0), 0),
    malls_crawled: items.map(i => i.json.mall_id).filter(Boolean),
    products: allProducts
  }
}];
